std::vector<PurchaseHistory> query_customer_purchase_history(int customer_id) {
  using namespace sqlgen::literals;

  // 1. Create database connection
  auto conn = sqlgen::sqlite::connect("test_db.sqlite");

  // 2. Create tables using sqlgen::write with empty containers
  std::vector<Customer> empty_customers;
  std::vector<Order> empty_orders;
  std::vector<OrderItem> empty_order_items;
  std::vector<Product> empty_products;

  sqlgen::write(conn, empty_customers);
  sqlgen::write(conn, empty_orders);
  sqlgen::write(conn, empty_order_items);
  sqlgen::write(conn, empty_products);

  // 3. Construct the query using sqlgen::read with proper joins and conditions
  auto query = sqlgen::read<std::vector<PurchaseHistory>>
    | sqlgen::join<Customer, "c">("customer_id"_c == "customer_id"_c)
    | sqlgen::join<Order, "o">("c.customer_id"_c == "o.customer_id"_c)
